					TypeParams: typeParamsString(ts),
					Deps:       depsFields,
				}); err != nil {
					return true
				}
				return true
			})

			if hasDecls {
				outputName := strings.TrimSuffix(filename, ".go") + "_sdi_gen.go"
				if err := writeGenerated(outputName, buf.Bytes()); err != nil {
