			}

			st, ok := ts.Type.(*ast.StructType)
			if !ok {
				return true
			}

			fields = append(fields, collectInterfaceFields(pkg, st)...)
			return true
		})
	}

	return fields
}

func collectInterfaceFields(pkg *packages.Package, st *ast.StructType) []depInfo {
	var deps []depInfo

	for _, field := range st.Fields.List {
