		}
		if !isInterface(pkg, field.Type) {
			continue
		}

		typName := getTypeName(pkg, field.Type)
		for _, name := range field.Names {
			deps = append(deps, depInfo{Name: name.Name, Typ: typName})
		}
	}

	return deps
}

func structEmbedsDeps(st *ast.StructType) bool {
