package main

import (
	"bytes"
	"fmt"
	"go/ast"
	"go/format"
	"go/printer"
	"go/types"
	"log"
	"os"
	"strings"
	"text/template"

	"golang.org/x/tools/go/packages"
)

const sdiTemplate = `
// Deps returns a list of dependencies required by {{.TypeName}}.
func (r *{{.TypeName}}{{.TypeParams}}) Deps() []any {
	return []any{
	{{- range .Deps}}
		(*{{.Typ}})(nil),
	{{- end}}
	}
}

// Inject sets the dependencies for {{.TypeName}}.
func (r *{{.TypeName}}{{.TypeParams}}) Inject(args []any) {
	for _, arg := range args {
		switch v := arg.(type) {
		{{- range .Deps}}
		case {{.Typ}}:
			r.{{.Name}} = v
		{{- end}}
		}
	}
}
`

type depInfo struct {
	Name string
	Typ  string
}

type structData struct {
	TypeName   string
	TypeParams string
	Deps       []depInfo
}

func main() {
	if err := Run("."); err != nil {
		log.Fatalf("error: %v", err)
	}
}

func Run(dir string) error {
	cfg := &packages.Config{
		Mode: packages.NeedName | packages.NeedFiles | packages.NeedSyntax | packages.NeedTypes | packages.NeedTypesInfo,
		Dir:  dir,
	}

	pkgs, err := packages.Load(cfg, ".")
	if err != nil {
		return fmt.Errorf("failed to load packages: %w", err)
	}

	tmpl, err := template.New("sdi").Parse(sdiTemplate)
	if err != nil {
		return fmt.Errorf("failed to parse template: %w", err)
	}

	for _, pkg := range pkgs {
		depsFields := findDepsStructFields(pkg)
		if len(depsFields) == 0 {
			continue
		}

		for _, file := range pkg.Syntax {
			filename := pkg.Fset.Position(file.Pos()).Filename
			if skipFile(filename) {
				continue
			}

			var buf bytes.Buffer
			hasDecls := false

			ast.Inspect(file, func(n ast.Node) bool {
				ts, ok := n.(*ast.TypeSpec)
				if !ok || ts.Name.Name == "deps" {
					return true
				}

				st, ok := ts.Type.(*ast.StructType)
				if !ok || !structEmbedsDeps(st) {
					return true
				}

				if !hasDecls {
					buf.WriteString(fmt.Sprintf("// Code generated by sdi. DO NOT EDIT.\npackage %s\n", pkg.Name))
					hasDecls = true
				}

				if err := tmpl.Execute(&buf, structData{
					TypeName:   ts.Name.Name,
					TypeParams: typeParamsString(ts),
					Deps:       depsFields,
				}); err != nil {
					return true
				}
